// frontend/src/components/StudentDashboard.jsx
import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import "./studentDashboard.css";

export default function StudentDashboard() {
  const studentId = localStorage.getItem("userId");

  // Tabs
  const [activeTab, setActiveTab] = useState("overview");

  // Data state
  const [student, setStudent] = useState(null);
  const [mentor, setMentor] = useState(null);
  const [mentors, setMentors] = useState([]);
  const [meetings, setMeetings] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [reports, setReports] = useState([]);

  // UI state
  const [loading, setLoading] = useState({
    student: false,
    mentors: false,
    meetings: false,
    availability: false,
    reports: false,
  });
  const [error, setError] = useState(null);

  // Project form
  const [projectData, setProjectData] = useState({
    mentor_id: "",
    project_title: "",
    description: "",
    domain: "",
    time_required: "",
    skills_required: "",
  });

  // Meeting booking
  const [selectedSlot, setSelectedSlot] = useState("");
  // Report upload
  const [selectedFile, setSelectedFile] = useState(null);

  // Small helper
  const setLoadingKey = (key, val) =>
    setLoading((prev) => ({ ...prev, [key]: val }));

  // -------- FETCHERS (each isolated & resilient) --------
  const fetchMentors = async () => {
    setLoadingKey("mentors", true);
    try {
      const res = await axios.get("/api/mentors"); // GET /api/mentors
      setMentors(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      console.error("Mentors fetch failed:", e);
      setError("Failed to load mentors.");
    } finally {
      setLoadingKey("mentors", false);
    }
  };

  const fetchStudent = async () => {
    if (!studentId) return;
    setLoadingKey("student", true);
    try {
      // You will implement GET /api/student/:id
      const res = await axios.get(`/api/student/${studentId}`);
      setStudent(res.data || null);

      // if API returns mentor_id on student
      if (res.data && res.data.mentor_id) {
        await fetchMentorById(res.data.mentor_id);
        await fetchAvailability(res.data.mentor_id); // prefetch assigned mentor’s slots
      } else {
        setMentor(null);
        setAvailability([]);
      }
    } catch (e) {
      console.error("Student fetch failed:", e);
      setError("Failed to load student info.");
    } finally {
      setLoadingKey("student", false);
    }
  };

  const fetchMentorById = async (mentorId) => {
    if (!mentorId) return;
    try {
      const res = await axios.get(`/api/mentors/${mentorId}`); // GET /api/mentors/:id
      setMentor(res.data || null);
    } catch (e) {
      console.error("Mentor by ID fetch failed:", e);
      setMentor(null);
    }
  };

  const fetchMeetings = async () => {
    if (!studentId) return;
    setLoadingKey("meetings", true);
    try {
      // You will implement GET /api/meetings/:student_id
      const res = await axios.get(`/api/meetings/${studentId}`);
      setMeetings(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      console.error("Meetings fetch failed:", e);
      setMeetings([]);
    } finally {
      setLoadingKey("meetings", false);
    }
  };

  const fetchAvailability = async (mentorIdParam) => {
    const mid = mentorIdParam || (mentor && mentor.sno);
    if (!mid) return;
    setLoadingKey("availability", true);
    try {
      // You will implement GET /api/availability/:mentor_id
      const res = await axios.get(`/api/availability/${mid}`);
      setAvailability(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      console.error("Availability fetch failed:", e);
      setAvailability([]);
    } finally {
      setLoadingKey("availability", false);
    }
  };

  const fetchReports = async () => {
    if (!studentId) return;
    setLoadingKey("reports", true);
    try {
      // You will implement GET /api/reports/:student_id
      const res = await axios.get(`/api/reports/${studentId}`);
      setReports(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      console.error("Reports fetch failed:", e);
      setReports([]);
    } finally {
      setLoadingKey("reports", false);
    }
  };

  // -------- EFFECTS --------
  // initial load: mentors + student + meetings + reports
  useEffect(() => {
    setError(null);
    fetchMentors();
    fetchStudent();
    fetchMeetings();
    fetchReports();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [studentId]);

  // if mentor changes, refresh availability
  useEffect(() => {
    if (mentor && mentor.sno) fetchAvailability(mentor.sno);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mentor?.sno]);

  // Useful map for dropdown rendering safety
  const mentorOptions = useMemo(
    () =>
      (mentors || []).map((m) => ({
        value: m.sno,
        label: `${m.facultyname} (${m.specialization || "—"})`,
      })),
    [mentors]
  );

  // -------- HANDLERS --------
  const handleProjectChange = (e) => {
    setProjectData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleProjectSubmit = async (e) => {
    e.preventDefault();
    setError(null);
    try {
      await axios.post("/api/mentor-requests", {
        ...projectData,
        student_id: studentId,
      }); // POST /api/mentor-requests
      alert("Project request submitted successfully!");
      setActiveTab("overview");
      // (Optional) refresh anything needed
    } catch (err) {
      console.error(err);
      setError("Error submitting project request.");
    }
  };

  const handleRequestFromMentorCard = (sno) => {
    setProjectData((prev) => ({ ...prev, mentor_id: String(sno) }));
    setActiveTab("project");
  };

  const handleSlotBooking = async () => {
    if (!selectedSlot) return alert("Please select a time slot.");
    const mid = mentor?.sno || projectData.mentor_id;
    if (!mid) return alert("No mentor selected/assigned.");

    try {
      const [date, time] = selectedSlot.split(" ");
      await axios.post("/api/meetings", {
        student_id: studentId,
        mentor_id: mid,
        meeting_date: date,
        meeting_time: time,
        topic: "Mentor Session",
        location: "College",
      }); // POST /api/meetings
      alert("Meeting booked successfully!");
      fetchMeetings();
      fetchAvailability(mid); // slot may now be booked
      setSelectedSlot("");
    } catch (e) {
      console.error(e);
      alert("Error booking meeting.");
    }
  };

  const handleReportUpload = async (e) => {
    e.preventDefault();
    if (!selectedFile) return alert("Please select a file first.");
    try {
      const mid = mentor?.sno || projectData.mentor_id || null;
      const fd = new FormData();
      fd.append("file", selectedFile);
      fd.append("student_id", studentId);
      if (mid) fd.append("mentor_id", mid);
      fd.append("title", selectedFile.name);

      await axios.post("/api/reports", fd, {
        headers: { "Content-Type": "multipart/form-data" },
      }); // POST /api/reports
      alert("Report uploaded successfully!");
      setSelectedFile(null);
      fetchReports();
    } catch (e) {
      console.error(e);
      alert("Error uploading report.");
    }
  };

  // -------- RENDER --------
  const greetingName =
    student?.name ||
    student?.student_name ||
    student?.Name ||
    "Student";

  return (
    <div className="student-dashboard">
      <h1>Student Dashboard</h1>

      {/* Top-level errors */}
      {error && (
        <div className="error-banner">
          {error}
        </div>
      )}

      <div className="tab-buttons">
        <button
          className={activeTab === "overview" ? "active" : ""}
          onClick={() => setActiveTab("overview")}
        >
          Overview
        </button>
        <button
          className={activeTab === "mentors" ? "active" : ""}
          onClick={() => setActiveTab("mentors")}
        >
          Mentors
        </button>
        <button
          className={activeTab === "project" ? "active" : ""}
          onClick={() => setActiveTab("project")}
        >
          Project
        </button>
      </div>

      {/* OVERVIEW */}
      {activeTab === "overview" && (
        <div className="overview-tab">
          <h2>Hello, {greetingName} 👋</h2>
          <p>
            <strong>Mentor:</strong>{" "}
            {mentor ? mentor.facultyname : "Not assigned yet"}
          </p>

          <div className="overview-sections">
            {/* Meetings */}
            <div className="section-card">
              <h3>Upcoming Meetings</h3>
              {loading.meetings ? (
                <p>Loading meetings…</p>
              ) : meetings.length === 0 ? (
                <p>No upcoming meetings</p>
              ) : (
                meetings.map((m) => (
                  <p key={m.id}>
                    {m.meeting_date} at {m.meeting_time} — {m.topic}
                  </p>
                ))
              )}

              <hr />
              <h4>Book a Slot</h4>
              {mentor ? (
                <>
                  {loading.availability ? (
                    <p>Loading availability…</p>
                  ) : availability.length === 0 ? (
                    <p>No available slots from your mentor.</p>
                  ) : (
                    <>
                      <select
                        value={selectedSlot}
                        onChange={(e) => setSelectedSlot(e.target.value)}
                      >
                        <option value="">Select slot</option>
                        {availability.map((a) => (
                          <option
                            key={a.id}
                            value={`${a.day} ${a.start_time}`}
                          >
                            {`${a.day} ${a.start_time} - ${a.end_time}`}
                          </option>
                        ))}
                      </select>
                      <button onClick={handleSlotBooking}>Book Meeting</button>
                    </>
                  )}
                </>
              ) : (
                <p>Assign/select a mentor to book meetings.</p>
              )}
            </div>

            {/* Reports */}
            <div className="section-card">
              <h3>Reports</h3>
              <form onSubmit={handleReportUpload}>
                <input
                  type="file"
                  onChange={(e) => setSelectedFile(e.target.files[0])}
                />
                <button type="submit">Upload Report</button>
              </form>
              <h4>Uploaded Reports</h4>
              {loading.reports ? (
                <p>Loading reports…</p>
              ) : reports.length === 0 ? (
                <p>No reports uploaded yet</p>
              ) : (
                <ul>
                  {reports.map((r) => (
                    <li key={r.id}>
                      {r.title} — {r.status}
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      )}

      {/* MENTORS */}
      {activeTab === "mentors" && (
        <div className="mentors-container">
          {loading.mentors ? (
            <p>Loading mentors…</p>
          ) : mentors.length === 0 ? (
            <p>No mentors found.</p>
          ) : (
            mentors.map((m) => (
              <div key={m.sno} className="mentor-card">
                <h3>{m.facultyname}</h3>
                <p><strong>Specialization:</strong> {m.specialization || "—"}</p>
                <p><strong>Email:</strong> {m.Email}</p>
                <p><strong>Designation:</strong> {m.designation || "—"}</p>
                <button onClick={() => handleRequestFromMentorCard(m.sno)}>
                  Request Mentor
                </button>
              </div>
            ))
          )}
        </div>
      )}

      {/* PROJECT */}
      {activeTab === "project" && (
        <div className="project-form project-vertical">
          <h3>Submit Project Idea</h3>
          <form onSubmit={handleProjectSubmit}>
            <label>Mentor:</label>
            <select
              name="mentor_id"
              value={projectData.mentor_id}
              onChange={handleProjectChange}
              required
            >
              <option value="">Select Mentor</option>
              {mentorOptions.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>

            <label>Project Title:</label>
            <input
              type="text"
              name="project_title"
              value={projectData.project_title}
              onChange={handleProjectChange}
              required
            />

            <label>Domain:</label>
            <input
              type="text"
              name="domain"
              value={projectData.domain}
              onChange={handleProjectChange}
            />

            <label>Time Required:</label>
            <input
              type="text"
              name="time_required"
              value={projectData.time_required}
              onChange={handleProjectChange}
            />

            <label>Skills Required:</label>
            <input
              type="text"
              name="skills_required"
              value={projectData.skills_required}
              onChange={handleProjectChange}
            />

            <label>Project Overview:</label>
            <textarea
              name="description"
              value={projectData.description}
              onChange={handleProjectChange}
              rows="4"
            ></textarea>

            <button type="submit">Submit Project</button>
          </form>
        </div>
      )}
    </div>
  );
}
